"""
This module defines the Piece class, which represents a single piece on the board.
"""

class Piece:
    def __init__(self, color, position, is_king=False):
        self.color = color
        self.position = position
        self.is_king = is_king

    def move(self, new_position):
        self.position = new_position

    def king(self):
        self.is_king = True
```

#### `board.py`
```python
"""
This module defines the Board class, which manages the game board state.
"""

from piece import Piece

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        colors = ['R', 'B']
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = Piece(colors[row % 2], (row, col))
        for row in range(5, 8):
            for col in range((7 - row) % 2, 8, 2):
                self.board[row][col] = Piece(colors[(row - 3) % 2], (row, col))

    def print_board(self):
        for row in self.board:
            print(" ".join([str(piece.color if piece else '--') for piece in row]))

# Example usage
if __name__ == "__main__":
    board = Board()
    board.print_board()
```

