"""
This module defines the Game class, which handles the overall game logic.
"""

from board import Board

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'R'

    def switch_turn(self):
        self.current_player = 'B' if self.current_player == 'R' else 'R'

    def play_game(self):
        while True:
            self.board.print_board()
            move_from = input(f"Player {self.current_player}, enter your move (from-to): ").split('-')
            from_pos, to_pos = tuple(map(int, move_from[0].split(','))), tuple(map(int, move_from[1].split(',')))
            if self.is_valid_move(from_pos, to_pos):
                self.board.print_board()
                self.switch_turn()
            else:
                print("Invalid move. Please try again.")

    def is_valid_move(self, from_pos, to_pos):
        # Implement move validation logic here
        return True

# Example usage
if __name__ == "__main__":
    game = Game()
    game.play_game()
```

